#!/usr/bin/env bash
# blur.sh — Blur 决策助手 for Figma 转 Photoshop (PSD).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Figma 转 Photoshop (PSD)"
TOPIC="Blur"

usage() {
  cat <<EOF
blur.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 2 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./blur.sh             # interactive
  ./blur.sh --dry-run   # walk through but no file
  ./blur.sh --json      # JSON to stdout
  ./blur.sh --explain   # show backing playbook rules + mental models
  ./blur.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Blur 主题下的 playbook 规则组合成交互树。

基于 2 条规则:
  • 如果 若有任何 blur → 乘换算系数后栅格化 → 则 ：Figma layer blur → PS 滤镜高斯按 **×0.431**；drop/inner shadow 的 
  • 如果 若有 background blur / Noise / Texture / 角向·菱形渐变 → 栅格化 → 则 ：background blur 无 PS 原生对应，须"拍平背景 → 在玻璃元素后放裁剪过的高斯副本(×0.431)"

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "若有任何 blur → 乘换算系数后栅格化"
  "若有 background blur / Noise / Texture / 角向·菱形渐变 → 栅格化"
)
declare -a RULE_ACTIONS=(
  "：Figma layer blur → PS 滤镜高斯按 **×0.431**；drop/inner shadow 的 blur 半径 ≈ 1:1 映射到 PS 的 Size，但 Figma \`spread\`(px) 要换成 PS Spread(% of size)、极坐标 offset 拆成 Distance+Angle。案例：50px Figma layer blur → PS 高斯填 ≈21.6px（不是直接填 50，否则糊一倍）。(evidence: [T01-S011, T01-S012, T06-S002])"
  "：background blur 无 PS 原生对应，须\"拍平背景 → 在玻璃元素后放裁剪过的高斯副本(×0.431)\"；Noise/Texture 是 Figma 新效果，PS 无 layer-style 对应。案例：毛玻璃导航条 → 拍平其后背景、放一个被导航条形状裁剪的高斯副本，而不是指望 PS 有\"背景模糊\"。(evidence: [T06-S002, T02-S004])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "blur-decision"
fi
